// Exemplo: usar watch para UI reativa
function MyWidget() {
  const [enabled, setEnabled] = useState(false);
  useEffect(() => {
    const sub = featureFlags.watch('myTool.myFeature').subscribe(v => setEnabled(v));
    return () => sub.unsubscribe();
  }, []);
  return enabled ? <EnabledUI/> : <DisabledUI/>;
}

